	)
		.then((r) => r.json())
		.then((d: GeoJSON.FeatureCollection<null, { place: string; mag: number }>) =>
			d.features.map((f) => {
				const c = geoCentroid(f);
				return {
					place: f.properties.place,
					magnitude: f.properties.mag,
					longitude: c[0],
					latitude: c[1]
				};
			})
		);
	return data;
});

